-- ============================================================
-- Tenure helper: completed months between hire_date and today.
-- Use as: SELECT employee_tenure_months(hire_date) FROM employees;
-- ============================================================
CREATE OR REPLACE FUNCTION employee_tenure_months(hire date)
RETURNS integer LANGUAGE sql IMMUTABLE AS $f$
  SELECT CASE
    WHEN hire IS NULL THEN NULL
    ELSE EXTRACT(YEAR FROM AGE(CURRENT_DATE, hire))::int * 12
       + EXTRACT(MONTH FROM AGE(CURRENT_DATE, hire))::int
  END
$f$;
